window.__QUIZ_SUBJECT__=[{"id": "theory>Marketing>2019>1>a", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "MERCHANDISING : ELEMENT", "question": "Miss Okon has just been employed by a consumer goods manufacturing company to merchandize it products at a retail outlet.  State four elements that would qualify the company's products to be merchandized at the retail outlet.", "images": [], "marking_scheme": "- The type of merchandise sold.  - Assortment localisation.  - Customer service.  - Pricing.", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2019>1>b", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "MERCHANDISING : FUNCTIONS", "question": "Miss Okon has just been employed by a consumer goods manufacturing company to merchandize it products at a retail outlet.  State six functions Miss Okon would perform as a merchandizer.", "images": [], "marking_scheme": "- Planning.  - Directing.  - Co-ordinating.  - Controlling.  - Forecasting.  - Assessing.", "marks": "12", "difficulty": "2"}, {"id": "theory>Marketing>2019>2>a", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "INTRODUCTION TO MARKETING : HISTORY", "question": "State five features of the post-independence era in the history of marketing in Nigeria.", "images": [], "marking_scheme": "- Consumer needs were most important things during this era.  - Marketing actually became the goal of business.  - This era makes customer to become a king.  - The development of technology result in emergence of mobile or social marketing era.  - This era give businesses to get access to potential and existing customers at any time they want.", "marks": "10", "difficulty": "3"}, {"id": "theory>Marketing>2019>2>b", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "INTRODUCTION TO MARKETING : FUNCTIONS", "question": "Explain **five* functions of marketing in Nigeria.", "images": [], "marking_scheme": "- Finding the best distribution channels   - Financing an enterprise   - Keep market research  - Setting prices  - Product and service management  - Promotional channels  - Matching products to customers.", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2019>3>a>i", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "Explain this concept in marketing: product concept", "images": [], "marking_scheme": "Product concept: This is the understanding of the dynamics of the product in order to showcase the best qualities and maximum features of the product. It propose that consumer will prefer products that have better quality, performance and features as opposed to a normal product.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2019>3>a>ii", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "Explain this concept in marketing: selling concept.", "images": [], "marking_scheme": "Selling concept: It proposes that customers be individual or organization will not buy enough of the organisation's product unless they are persuaded to do so through selling effort.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2019>3>a>iii", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "iii", "group": "CLOSENESS", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "Explain this concept in marketing: production concept.", "images": [], "marking_scheme": "Production concept: It is the oldest of the concepts in business. It holds that consumers will prefer product that are widely available and inexpensive. It concentrate on achieving high production efficiency, low cost, mass distribution.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2019>3>a>iv", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "iv", "group": "CLOSENESS", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "Explain this concept in marketing: societal marketing concept.", "images": [], "marking_scheme": "Societal marketing concept: It is a marketing concept that holds that a company should make marketing decisions not only by considering consumer's wants, the company's requirement but also society's long-term interests.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2019>3>b>i", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "i", "group": "FINAL", "topic": "PRICING : APPLICATION", "question": "A product costs ₦4,000 to produce. The producer decides to sell the product for ₦6,000. Calculate the markup.", "images": [], "marking_scheme": "Mark-up = Selling price - Cost price   ⇒ 6000 - 4000 = ₦2000", "marks": "4", "difficulty": "1"}, {"id": "theory>Marketing>2019>3>b>ii", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "ii", "group": "FINAL", "topic": "PRICING : APPLICATION", "question": "A product costs ₦4,000 to produce. The producer decides to sell the product for ₦6,000. Calculate the percentage markup on cost.", "images": [], "marking_scheme": "Percentagemarkuponcost=Mark-upCost price×1001  =20004000×100 = 50%", "marks": "4", "difficulty": "1"}, {"id": "theory>Marketing>2019>3>b>iii", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "iii", "group": "", "topic": "PRICING : APPLICATION", "question": "A product costs ₦4,000 to produce. The producer decides to sell the product for ₦6,000. Calculate the percentage markup on selling price.", "images": [], "marking_scheme": "*percentagemarkuponsellingprice*=MarkupSelling price×1001  =20006000*Times*100=33.3%", "marks": "4", "difficulty": "2"}, {"id": "theory>Marketing>2019>4>a", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "ENTREPRENUERSHIP IN MARKETING : MEANING OF ENTREPRENEURSHIP", "question": "What is entrepreneurship?", "images": [], "marking_scheme": "Entrepreneurship is the process of designing, launching and running a new business, which is often initially a small business. The people who create these businesses are called Entrepreneurs.", "marks": "2", "difficulty": "1"}, {"id": "theory>Marketing>2019>4>b", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ENTREPRENUERSHIP IN MARKETING : SELLING AND BARGAINING SKILLS", "question": "State four selling skills required by an entrepreneur.", "images": [], "marking_scheme": "- Basic human psychology  - Listening skills  - Prospect filtering  - Strategic positioning  - Unique selling proposition  - Creativity  - Risk taking", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2019>4>c", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "ENTREPRENUERSHIP IN MARKETING : MANAGEMENT OF MARKET OUTLETS", "question": "State fiveactivities to be performed by an entrepreneur to ensure successful operation of his market outlet.", "images": [], "marking_scheme": "- Have a written plan  - Do not marry your plan.  - Keep your ego in check and listen to others.  - Keep track of everything, and manage by the numbers.  - Delegate to employees and avoid micro-managing them.  - Use the Internet.  - Re-invent your business.", "marks": "10", "difficulty": "3"}, {"id": "theory>Marketing>2019>5>a", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "ADVERTISING : DEFINITION", "question": "What is advertising?", "images": [], "marking_scheme": "Advertising: It is a marketing communication that employs an openly sponsored, non-personal message to promote or sell a product, service or idea.", "marks": "2", "difficulty": "1"}, {"id": "theory>Marketing>2019>5>b", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "Identify any six media of advertising.", "images": [], "marking_scheme": "- Television  - Radio  - Newspaper  - Magazine  - Bill board  - Leaflet or Handbills.", "marks": "6", "difficulty": "2"}, {"id": "theory>Marketing>2019>5>c", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "Explain four disadvantages of advertising.", "images": [], "marking_scheme": "- It adds to cost of production  - It undermines social values  - It confuses the buyers  - It encourages sale of inferior products  - Some advertisement is the bad taste.", "marks": "12", "difficulty": "2"}, {"id": "theory>Marketing>2019>6>a", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "WAREHOUSING : ACTIVITIES IN THE WAREHOUSING", "question": "State four functions of warehousing.", "images": [], "marking_scheme": "- It serves as storage facilities.  - It stabilise price.  - It store surplus goods.  - Minimisation of risk.  - Packing and grading.  - Financing.", "marks": "4", "difficulty": "2"}, {"id": "theory>Marketing>2019>6>b>i", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "TRANSPORTATION : MEANING,MODE, CHOICE AND IMPORTANCE", "question": "List three modes of transportation.", "images": [], "marking_scheme": "- Air transportation  - Land transportation  - Sea/water transportation.", "marks": "4", "difficulty": "1"}, {"id": "theory>Marketing>2019>6>b>ii>I", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "I", "group": "CLOSENESS", "topic": "TRANSPORTATION : DOCUMENTS USED IN TRANSPORTATION", "question": "Explain this transportation document:   Waybill", "images": [], "marking_scheme": "Waybill: It is a paper giving a list of goods and shipping instructions, sent with the goods being shipped. It is a document attached to goods in transit specifying their nature, point of origin, and destination as well as the route to be taken and the rate to be charged.", "marks": "4", "difficulty": "2"}, {"id": "theory>Marketing>2019>6>b>ii>II", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "II", "group": "CLOSENESS", "topic": "TRANSPORTATION : DOCUMENTS USED IN TRANSPORTATION", "question": "Explain this transportation document:  consignment note", "images": [], "marking_scheme": "Consignment note: It is a document prepared by a consignor and countersigned by the carrier as a proof of receipt of consignment for delivery at the destination.", "marks": "4", "difficulty": "1"}, {"id": "theory>Marketing>2019>6>b>ii>III", "subject": "Marketing", "year": "2019", "type": "Theory", "sub_label": "III", "group": "CLOSENESS", "topic": "TRANSPORTATION : DOCUMENTS USED IN TRANSPORTATION", "question": "Explain this transportation document;   Delivery note.", "images": [], "marking_scheme": "Delivery note: It is a document accompanying a shipment of goods that lists the description and quantity of goods delivered. It shows that a good has been delivered to the customer.", "marks": "4", "difficulty": "1"}, {"id": "theory>Marketing>2020>1>a", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "Oliver Ltd, a producer of fruit juice sells its products to stores across the country.    List six advertising media the company could use to create awareness about its products", "images": [], "marking_scheme": "- Television  - Radio  - Magazine  - Newspapers  - Product placement  - Internet", "marks": "5", "difficulty": "2"}, {"id": "theory>Marketing>2020>1>b", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ADVERTISING : FUNCTIONS", "question": "Oliver Ltd, a producer of fruit juice sells its products to stores across the country.State three benefits the company would derive from advertising the products", "images": [], "marking_scheme": "- The revenue/turnover of the company will increase    - Consumers will be aware of the new product feature or price    - To increase market share    -", "marks": "5", "difficulty": "2"}, {"id": "theory>Marketing>2020>1>c", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "TRANSPORTATION : FACTORS AFFECTING CHOICE OF TRANSPORTATION", "question": "Oliver Ltd, a producer of fruit juice sells its products to stores across the country.State four factors that would influence the company's choice of mode of transporting its products", "images": [], "marking_scheme": "- Cost of service  - Speed of transport  - Nature of commodity  - Regularity of services", "marks": "5", "difficulty": "2"}, {"id": "theory>Marketing>2020>2>a>i", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "PRODUCTS : DISTINCTION BETWEEN CLASSES OF PRODUCTS", "question": "Distinguish between:    -  primary product and secondary product;", "images": [], "marking_scheme": "Primary product is a product that is essential in providing solution to a specific problem customer seeks to resolve while secondary product is a product that is not essential to solving customer's problem.", "marks": "5", "difficulty": "3"}, {"id": "theory>Marketing>2020>2>a>ii", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "MARKET UNIONS AND FACILITATORS : MARKET FACILITATORS ( MEANING, TYPES AND ROLES)", "question": "Distinguish between:market facilitator and market union", "images": [], "marking_scheme": "Market facilitator is a consultant whose primary function is to stimulate markets while remaining outside of the market themselves while market union refers to various trade who sell similar commodities or product in a particular market.", "marks": "5", "difficulty": "3"}, {"id": "theory>Marketing>2020>2>b", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "MARKET UNIONS AND FACILITATORS : MARKET FACILITATORS ( MEANING, TYPES AND ROLES)", "question": "Distinguish between:List four market facilitators and state one function of each in aiding the activities of marketers", "images": [], "marking_scheme": "- Advertising agency: These are agents that help to expose the product to the consumers through advertising media such as television,radio etc    - Market research firm: These are agents that gather information about a market's size for the purpose of introducing the products to the customers    - Transportation firm: They help to transport the product to the customers or consumers    - Insurance brokers and agents: They sell the goods or product on behalf of the marketing firm.", "marks": "5", "difficulty": "3"}, {"id": "theory>Marketing>2020>3>a", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "INTERNATIONAL MARKETING : INFLUENCING FACTORS", "question": "Joan Ltd, a product of cosmetic products, has decided to engage in international marketing of its products    -  State five factors that may have influenced Joan Ltd's decision to go international", "images": [], "marking_scheme": "- The possibilty of increasing revenue of the company    - The presence of new customers base    - Expansion of the business    - To gain competitive advantage    - Lower operational cost", "marks": "7", "difficulty": "2"}, {"id": "theory>Marketing>2020>3>b", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "INTERNATIONAL MARKETING : GUIDING RULES AND REGULATIONS", "question": "Joan Ltd, a product of cosmetic products, has decided to engage in international marketing of its productsState five rules and regulations the company would observe while selling its products in other countries", "images": [], "marking_scheme": "- The company must learn all the prohibitions and laws of the country    - The law governing the country advertising    - Promotion mechanics rules and regulation    - Tax system rules and regulation of the country    - Shipping rules and regulation", "marks": "8", "difficulty": "3"}, {"id": "theory>Marketing>2020>4>a", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "MARKETING PLANNING AND RESEARCH : REASONS FOR MARKETING PLANNING AND RESEARCH", "question": "Audu Ltd, a trading company,has just set up a committee to conduct a marketing research for the company    - State five reasons that would have necessitated the conduct of the research", "images": [], "marking_scheme": "- To Identify the problems areas in the business    - To understand the needs of existing customers    - To identify new business opportunities and changing market trends    - To recognize new areas for expansion and increase customer base    - To discover potential customers and their needs,which can be incorporated into the services.", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2020>4>b", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING", "question": "Audu Ltd, a trading company,has just set up a committee to conduct a marketing research for the companyState five steps the committee would take in carrying out the assignment", "images": [], "marking_scheme": "- Identifying and defining the problem    - Statement of research objectives    - Planning the research design     - Planning the sample    - Data collection, processing and analysis", "marks": "7", "difficulty": "3"}, {"id": "theory>Marketing>2020>5>a", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "ADVERTISING : PRODUCTION OF SAMLE ADVERTS", "question": "Use the advert in Figure 1 below to answer the following questions.      List six items that would be found on the package of the product labelled A", "images": ["Marketing/imgs/2020/sscemark2020q5a.png"], "marking_scheme": "- Name of the product  - Expiry date  - Ingredients  - Weight  - manufacturer's contact details  - Direction/Instruction for usuage", "marks": "5", "difficulty": "2"}, {"id": "theory>Marketing>2020>5>b", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ADVERTISING : FUNCTIONS", "question": "Use the advert in Figure 1 below to answer the following questions.   State three functions of the part labelled B", "images": ["Marketing/imgs/2020/sscemark2020q5a.png"], "marking_scheme": "- To give information about the product    - To inform the users about the value of the product    - To build brand preference in the market", "marks": "5", "difficulty": "2"}, {"id": "theory>Marketing>2020>5>c", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "Use the advert in Figure 1 below to answer the following questions.   State four advantages of using this medium to advertise the product", "images": ["Marketing/imgs/2020/sscemark2020q5a.png"], "marking_scheme": "- It offers sight, action and sound benefit to the customer    - It provided recreation to the viewers    - It gives high in-the-room intimacy and can present national coverage on network    - The product is visibly demonstrated to appeal to the target audience.", "marks": "5", "difficulty": "3"}, {"id": "theory>Marketing>2020>6>a", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER", "question": "Outline four differences between organizational buying behaviour and consumer buying behaviour", "images": [], "marking_scheme": "- The organizations buy goods and services for their business needs while the individual consumers buy goods and services for ultimate use or satisfy their needs    - Organizational buying is done in large quantities while consumer buy various kinds of goods.The quantity of goods remains small.    - Organizational purchasing is a rational process because the purchasing behaviour of organizations is guided by objective factors while consumer buying takes decisions by consumers themselves    - Organizational purchase criteria are specifically defined while consumer may not have adequate knowledge and information about the market situation", "marks": "7", "difficulty": "3"}, {"id": "theory>Marketing>2020>6>b", "subject": "Marketing", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : INFLUECING FACTORS", "question": "List and explain three influencing factors in organizational buying behaviour.", "images": [], "marking_scheme": "- Economic  factors  - Technological factors  - Political and legal factors    - Economic factors: It includes the level of demand,economic condition,competition,change in technology, trade cycle etc. The change in the general economic conditions of a market affects the demand for organizational products which is related to the demand for consumer products.    Technological factors: Technological factors such as the development of e-commerce,  development of information, development of internet have brought changes in institutional buying and inventory management,production process,distribution management etc    - Political and legal factors: Institutions may be affected by political and legal factors.Every organization has to operate their activities according to the rules and regulation of the nation so while buying goods and services organization should study about the political system,political situation,political ideology,government policies etc.", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2021>1>a", "subject": "Marketing", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "ENTREPRENUERSHIP IN MARKETING : FACTORS AFFECTING LOCATION OF A MARKET OUTLET", "question": "Mr.Abu, an entrepreneur, wants to establish a public warehousing business.    - State five factors to be considered by Mr.Abu in locating the business", "images": [], "marking_scheme": "- Rent, Rates & Taxes   - Workforce availability, labour skills and costs   - Road, Highways and Traffic flow   - Proximity to Airport, Railway stations and Ports   -Markets and local -environment factors   - Building availability and utitlity costs   - Operation cost   - Nearness to distribution", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2021>1>b", "subject": "Marketing", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "WAREHOUSING : ACTIVITIES IN THE WAREHOUSING", "question": "Mr.Abu, an entrepreneur, wants to establish a public warehousing business.    - Desribe five activities to be carried out by Mr.Abu in the business", "images": [], "marking_scheme": "- Receiving: operations that involve the assignment of trucks to ducks, the scheduling and execution of unloading activities     - Storing: Material's movement from unloading area to its designated place in inventory     - Order pick; the process of obtaining the right amount of the right products for a set of customer orders. This is the main and the most labour-intensive activity of warehose     - Shipping: execution of packing and truck's loading after picking, involving also the assignment of trucks to docks     - Delivery: the transit time for transportation from the warehouse to the customer.", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2021>2>a", "subject": "Marketing", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "ICT IN MARKETING : USES, ETHICS AND ABUSES", "question": "State five ways e-marketing can be abused?", "images": [], "marking_scheme": "- By chatting with unknown people     - By sending and receiving pornography     - By using bad languages for e-marketing     - By changing the internet address     - By pretending to be someone else     - By changing the voice mode while chatting     - Internet fraud and lack of regulation     - Lack of ethics and hoaxes", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2021>2>b", "subject": "Marketing", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ICT IN MARKETING : E-MARKETING - MEANING, IMPORTANCE", "question": "Ajax LTD is a marketing company that intends to reach its customer through email.   Explain five important of email to Ajax ltd operation?", "images": [], "marking_scheme": "- It will help to reduces the code of advertisement to Ajax LTD     - It will helps the company to track the rate of return on their investment     - It will helps to research on many customers at the same time     - It will enables Ajax LTD to personalize message effectively     - It will helps the company to know the number of their customers effectiviely     - It will build customer relationship even with the past customers     - It is cost effective and permission based", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2021>3>a", "subject": "Marketing", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PRODUCTS : PRODUCT DESIGN", "question": "Use the diagram to answer question 3(a), 3(b) and 3(c).       - Identify the parts of the product labelled A, B, C and D", "images": ["Marketing/imgs/2021/img19.png"], "marking_scheme": "- Part A is Packaging     - Part B is Brand name     - Part C is Labelling     - Part D is the symbol or logo", "marks": "4", "difficulty": "3"}, {"id": "theory>Marketing>2021>3>b", "subject": "Marketing", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "PRODUCTS : MEANING", "question": "Use the diagram to answer question 3(a), 3(b) and 3(c).         - State three functions of the part labelled A to the product", "images": ["Marketing/imgs/2021/img19.png"], "marking_scheme": "- It makes advertsing easy     - It facilitates self-service, retailing and mail order business     - It protect the products as they move from producers to sellers and to the final consumers     - It makes for easy handling     - The middlemen are relieved of the burden of having to prepackage the goods", "marks": "6", "difficulty": "2"}, {"id": "theory>Marketing>2021>3>c", "subject": "Marketing", "year": "2021", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "PRODUCTS : MEANING", "question": "Use the diagram to answer question 3(a), 3(b) and 3(c).         - Explain five importance of the part labelled C to the consumer", "images": ["Marketing/imgs/2021/img19.png"], "marking_scheme": "- Information: It informs the customers about the existence of a product.     - Selection: Branding facilitaes self selection and useful for introducing new product     - Pricing: Branding encourages standardised pricing     - Quality of product: Branding is an assurance that the quality of the product will be maintained     - Recognition: It ensure easy recognition of product     - Market segementation: It makes market segementation easier as different brands similar products developed to meet the needs of specific categories of people.", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2021>4>a", "subject": "Marketing", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "SALES PROMOTION : MEANING AND FUNCTIONS", "question": "Ozayi Ltd is a new manufacturing company producing consumer goods. The company intends to gain market shares by using sales promotion.    - Outline four importance of sales promotion to the company", "images": [], "marking_scheme": "- It helps to build the database     - It will help to increase frequency or quantity of purchase     - it can help to cross sell and enforce brand     - it helps to encourage customers to try your products", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2021>4>b", "subject": "Marketing", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "SALES PROMOTION : FORMS", "question": "Ozayi Ltd is a new manufacturing company producing consumer goods. The company intends to gain market shares by using sales promotion.    - List and explain four sales promotional tools that can be used by the company.", "images": [], "marking_scheme": "- Free sample distribution   - Special prices sales   - premium offer   - Competitions   - Trade fairs     -Free sample distribution: Giving out free goods bearing their logo to some of their customers to maintain goodwill and this is good for new products     - Special price sale: This is the process of reducing the price of a product's regular packaging by stating the price reduction in the goods or by selling three products at the price of two.     - Premium offer: Offer a low value of item as a bonus to purchasers of a product, e.g biro or tooth brush in a tooth paste.     -Competition: Customers can be invited to participate in contest, lotteries, raffles in which a fraction of them will win prizes.     - Trade fairs: Displaying samples of the firms product and the literature about the product are given to the enquiring customers.", "marks": "12", "difficulty": "3"}, {"id": "theory>Marketing>2021>5>a", "subject": "Marketing", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING", "question": "State five importance of marketing planning to an organization", "images": [], "marking_scheme": "- Marketing planning provides direction for all organization marketing effort     - Marketing planning help organization to raise finance for capital expenditure     - Marketing planning prevents time wasting on ineffective marketing activities     - It save money by helping to ensure that the marketing budget is spent effectively     - It helps to identify, prerequistes to planned activities     - It helps to generate more clients by communicating effectively", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2021>5>b>i", "subject": "Marketing", "year": "2021", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "MARKET UNIONS AND FACILITATORS : MARKET UNIONS ( MEANING AND TYPES)", "question": "Mrs Janet, a dry fish seller, formed an organization with other dry fish sellers for their common interest in a local market.    Identify the organization formed by Mrs Janet with other dry fish sellers.", "images": [], "marking_scheme": "The organization formed by Mrs Janet with other dry fish sellers is World Trade Organization(WTO)", "marks": "2", "difficulty": "1"}, {"id": "theory>Marketing>2021>5>b>ii", "subject": "Marketing", "year": "2021", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "MARKET UNIONS AND FACILITATORS : ROLES OF MARKET UNIONS", "question": "Mrs Janet, a dry fish seller, formed an organization with other dry fish sellers for their common interest in a local market.    - State four functions the organization would perform to its members.", "images": [], "marking_scheme": "- Overseeing trade agreement     - Reducing trade barriers     - Reducing worldwide tarrifs     - Mediating dispute", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2021>6>a", "subject": "Marketing", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : MEANING", "question": "Abu Company Ltd manufacturers and sells hospital equipment to organizational markets.    - State four features of the markets the company sells its products to", "images": [], "marking_scheme": "- Derived demand     - High concentration of production     - Direct channel of distribution     - Few Buyers and large Volume     - Professional buying", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2021>6>b", "subject": "Marketing", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "MARKETS : CLASSIFICATION", "question": "Abu Company Ltd manufacturers and sells hospital equipment to organizational markets.     - List and explain three types of the market the company sells to.", "images": [], "marking_scheme": "- Industrial market: it involves set of all individuals and organizations that acquire goods and services that enter into the production of other products or services that are sold, rented, or supplied to others.     - Reseller market: A market consisting of wholesalers and retailers who buy products for resale purposes. Resellers buy finished goods and resell them to the next level in a given distribution channel.     - Government channel: A government market is a market where the main buyers are federal, state, and local governmental organizations. They purchase goods or services from private businesses.", "marks": "12", "difficulty": "3"}, {"id": "theory>Marketing>2022>1>a>i", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "ENTREPRENUERSHIP IN MARKETING : MEANING OF ENTREPRENEURSHIP", "question": "What is entrepreneurship?", "images": [], "marking_scheme": "Entrepreneurship refers to the concept of developing and managing a business venture in order to gain profit by taking several risks in the corporate world.", "marks": "2", "difficulty": "1"}, {"id": "theory>Marketing>2022>1>a>ii", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "ENTREPRENUERSHIP IN MARKETING : SOURCES OF FUNDS", "question": "List and explain four sources of fund to an entrepreneur", "images": [], "marking_scheme": "-Retained earnings  - Debt capital   - Equity capital  - Personal investment    - RETAINED EARNINGS:  Business aim to maximize profits by selling a product or rendering service for the higher than what it costs them to produce the goods. It is the most primitive source of funding for any company.    - DEBT CAPITAL:  Companies obtain debt financing privately through bank loans. They can also source new funds by issuing debt to the public.    - EQUITY CAPITAL:  Companies can raise funds from the public in exchange for a proportionate ownership stake in the company in the form of shares issued to investors who become shareholders after purchasing the shares.    - PERSONAL INVESTMENT:   When starting a business, your first investor should be yourself either with your own cash or with collateral on your assets. This proves to investors and bankers that your project and that you are ready to take risks.", "marks": "12", "difficulty": "2"}, {"id": "theory>Marketing>2022>1>b", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ENTREPRENUERSHIP IN MARKETING : FACTORS AFFECTING LOCATION OF A MARKET OUTLET", "question": "Outline six factors influencing the choice of location of market outlet", "images": [], "marking_scheme": "- Availability of raw materials    - Nearness to market    - Availability of basic infrastructure    - Economic policy    - Demographics    - Psychographics", "marks": "6", "difficulty": "2"}, {"id": "theory>Marketing>2022>2>a>i", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "INTRODUCTION TO MARKETING : MEANING OF MARKETING", "question": "What is marketing?", "images": [], "marking_scheme": "Marketing is the process of exploring, creating, and delivering value to meet the needs of a target market in terms of goods and services.", "marks": "2", "difficulty": "1"}, {"id": "theory>Marketing>2022>2>a>ii", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "INTRODUCTION TO MARKETING : FUNCTIONS", "question": "Outline six functions of marketing", "images": [], "marking_scheme": "- Promotion    - Selling    - Product/Service    - Management    - Marketing information management    - Pricing", "marks": "6", "difficulty": "2"}, {"id": "theory>Marketing>2022>2>b", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "List and explain four marketing concepts", "images": [], "marking_scheme": "- The production concept    - The product concept    - The selling concept    - The marketing concept      - THE PRODUCTION CONCEPT:  The production concept focused on operations and is based on the assumption that consumers will be more attracted to products that are readily available and can be purchased for less than competing products of the same kind.    - THE PRODUCT CONCEPT:  The product concept is the opposite of the production concept in that it assumes that availiability and price don't have a role in customer buying habits and that people generally prefer quality, innovation, and performance over low cost.    - THE SELLING CONCEPT:  Marketing on the selling concept entails a focus on getting the consumer to the actual transaction without regard for the consumer's needs or the product quality a costly tactic.    - THE MARKETING CONCEPT:  The marketing concept is based on increasing a company's ability to compete and achieve maximum profits by marketing the ways in which it offers better value to cutomers than its competitors.", "marks": "12", "difficulty": "2"}, {"id": "theory>Marketing>2022>3>a", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "a", "group": "", "topic": "WAREHOUSING : ACTIVITIES IN THE WAREHOUSING", "question": "Amaka decided to establish a warehosuing business.    State five activities Amaka is expected to carry out in the business", "images": [], "marking_scheme": "- Receiving: Operations that involve the assignment of trucks to docks, the scheduling and execution of unloading activities.    - Storing: Material's movement from unloading area to its designated place in inventory    - Order picking: This is the main and the most labour-intensive activity of warehouses. Amaka will be obtaining the right amount of the right products for a set of customers orders.    - Shipping: Execution of packing and truck's loading after picking involving also the assignment of trucks to docks.    - Delivery: The transit time for transportation from the warehouse o the customer is part of the activities that is carried out in Amaka's warehouse.", "marks": "10", "difficulty": "3"}, {"id": "theory>Marketing>2022>3>b", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ICT IN MARKETING : USES, ETHICS AND ABUSES", "question": "Amaka decided to establish a warehosuing business.  State five e-marketing ethics Amaka could adopt for her warehousing business", "images": [], "marking_scheme": "- She must adopt responsibility for the consequences of their activities and make every to ensure that their decisions, recommendations, and actions function to identify, serve, and satisfy all relevant public.    - Amaka should give a maximum privacy to every customer on internet by not bombarding potential customers wih unwanted solicitations and information provide customers.    - She should have a good customer service or commitment by notifying the customer immediately of items that are out of stock,  have been discontinued , or other updates.    - She should avoid copyright issues by asking for permission before using someone's site or material    - She should ensure the security of her customers, making sure their personal information is not be traded or sold without permission.", "marks": "10", "difficulty": "3"}, {"id": "theory>Marketing>2022>4>a>i", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "INTRODUCTION TO MARKETING : BASIC TERMS", "question": "Explain the following terms in marketing:    needs", "images": [], "marking_scheme": "Need is a customer's desire for a product's or service's specific benefit, whether that be functional or emotional.", "marks": "2", "difficulty": "1"}, {"id": "theory>Marketing>2022>4>a>ii", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "INTRODUCTION TO MARKETING : BASIC TERMS", "question": "Explain the following terms in marketing:  wants", "images": [], "marking_scheme": "Want is the desire for products or services that are not necesary, but which consumers wish for.", "marks": "2", "difficulty": "1"}, {"id": "theory>Marketing>2022>4>a>iii", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "iii", "group": "CLOSENESS", "topic": "INTRODUCTION TO MARKETING : BASIC TERMS", "question": "Explain the following terms in marketing:  exchange", "images": [], "marking_scheme": "Exchange is a marketplace where securities, commodities, derivatives and other financial instruments are traded.", "marks": "2", "difficulty": "1"}, {"id": "theory>Marketing>2022>4>a>iv", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "iv", "group": "CLOSENESS", "topic": "INTRODUCTION TO MARKETING : BASIC TERMS", "question": "Explain the following terms in marketing:  demand", "images": [], "marking_scheme": "Demand is the total quantity of goods and services demanded across all consumers in a market for a given period.", "marks": "2", "difficulty": "1"}, {"id": "theory>Marketing>2022>4>a>v", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "v", "group": "CLOSENESS", "topic": "INTRODUCTION TO MARKETING : BASIC TERMS", "question": "Explain the following terms in marketing:  transaction", "images": [], "marking_scheme": "Transaction  is a completed agreement between a buyer and a seller to exchange goods, services , or financial assets in return for money.", "marks": "2", "difficulty": "1"}, {"id": "theory>Marketing>2022>4>b", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ADVERTISING : PRODUCTION OF SAMLE ADVERTS", "question": "Okon Enterprises Ltd sells electronics appliances at his retail outlet at No. 4 Okeke Adamu Street , Lagos. Telephone No.; 06012345678.  He intends to offer 15% discount to encourage the sales of his newly introduced Blenders, Television and Radio sets.     You are required to design a sample fo a handbill showing the products with the advertising message.", "images": [], "marking_scheme": "SPECIAL OFFER                                                                                  OKON ENTERPRISES LIMITED  Dealers in top Electronic Appliance in Nigeria like LG, SAMSUNG, SONY, HISENSE, THERMOCOOL. We sell Smart Television, Washing machine, Generator, Blenders, Microwave and lots more.    STORE: NO 4 Okeke Adamu street, Lagos    CONTACT: 06012345678    15% AMAZING DISCOUNT    YES, THAT'S RIGHT    Enjoy this discount on our newly available Blenders, Television and Radio Sets.    You can't beat the dial.", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2022>5>a", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "TRANSPORTATION : FACTORS AFFECTING CHOICE OF TRANSPORTATION", "question": "Adamu, a wholesaler in Lagos, who deals in frozen foods has customers in the northern parts of the country.    State four factors that would affect the choice of the mode of transporting the goods to his customers", "images": [], "marking_scheme": "- The nature of the goods to be transported will determine the means of transportation to be used. Perishable and fragile goods for example are better handled by fast means of transportation like aircraft while bulky goods are better handled by ship or rail.    - The overall cost of transport does determine the choice of means of transportation of goods. Air transport is costly while rail is cheap over a long distance and this will determine the choice of the two to use.    -  When the distance is long, the best means of transportation are water and airm irrespective of the cost while road transportation is good over short distance.    - Goods that are heavy and bulky are better moved by road, rail and sea while light goods are best suited for air transport.", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2022>5>b", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "TRANSPORTATION : DOCUMENTS USED IN TRANSPORTATION", "question": "Adamu, a wholesaler in Lagos, who deals in frozen foods has customers in the northern parts of the country.  List and explain four transportation documents he would use in the course of delivering the goods to his customers", "images": [], "marking_scheme": "-  Consigment note  - Bill of lading  - Certificate of insurance  - Airway bill    - CONSIGNMENT NOTE:   Consignment note is a document made out by the sender of goods handed to the carrier, and countersigned by the consignee on delivery as proof that delivery has been made.    - BILL OF LADING:  A bill of lading is a document that gives the holder the right to acquire possession of goods that have been shipped. It shows the name of the vessel, the port of destination and the rate of freight.    - CERTIFICATE OF INSURANCE:  Certificate of insurance is a document which shows that goods have been insured against risks or loss by the exporter.    - AIRWAY BILL:  Airway bill is a document made out by the consignor of goods to be transported by air. It shows the names of consignor and consigness, the airport of loading and the value of the goods.", "marks": "12", "difficulty": "2"}, {"id": "theory>Marketing>2022>6>a", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : FACTORS AFFECTING MARKETING ENVIRONMENT", "question": "Mr.Okon is planning to establish a noodle manufacturing company. He observed that the market for the product is large with many customers.    List and explain four external marketing environmental factors that would affect his business.", "images": [], "marking_scheme": "- Supplier include all the parties which provide resources needed by the organisation    -Market intermediaries include parties involved in distributing the product or service of the organisation and public is made up of any other group that has an actual or potential interest or affects the company's ability to serve its customers.    - Partners are all the separate entities like advertising agencies, market research organisations, banking and insurance companies, transportation companies, brokers etc which conduct business with the organisation    - Customers comprise of the traget group of the organisation and competitors are the players in the same market who tragets similar customers as that of the organisations.", "marks": "12", "difficulty": "3"}, {"id": "theory>Marketing>2022>6>b", "subject": "Marketing", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "SALES PROMOTION : MEANING AND FUNCTIONS", "question": "Mr.Okon is planning to establish a noodle manufacturing company. He observed that the market for the product is large with many customers.  Explain four sales promotional tools he would use to introduce his new products to the market", "images": [], "marking_scheme": "- Loyal customer: Offer loyal customers an exclusive preview. Your loyal customers are a key part of how to promote your product, because they are most likely to not only buy it, but also promote it to their networks.    - Special introductory: Use a special introductory offer rather than just announcing your new product or service, you can make it available as a part of a special introductory deal.    - Run a social media contest: Social media contests are fun, easy way of connecting with customers and bringing in more fans/followers and prospects for your business    - Host an event: Events not only get customers excited about your new product or service, but can also get new prospects personally engaging with you or other employees of your business a great way to win them over as customers.", "marks": "8", "difficulty": "3"}, {"id": "theory>Marketing>2023>1>a", "subject": "Marketing", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "ADVERTISING : FUNCTIONS", "question": "State five functions of a wholesaler", "images": [], "marking_scheme": "- Wholesalers purchase goods in large quantities from manufacturers or producers. They buy goods in bulk at discounted prices, leveraging their buying power to negotiate favourable terms and conditions.    - wholesalers maintain an inventory of goods to ensure a steady supply to retailers. They forecast demand, monitor trends, and stock a wide range of products to meet the varied needs of retailers.    - Wholesalers provide warehousing facilities to store and protect goods. They handle logistics, including receiving, storing, and organizing inventory eficiently.    - Wholesalers may inspect, sort, and grade the products they receive from manufacturers. This ensures that the products meet certain quality standards and are appropriately categorized before being distributed to retailers.    - Wholesalers repackage products to make them suitable for retail sale. They may remove bulk packaging and repackaging products into smaller units or create customized packaging solutions as per the requirements of retailers.    - Wholesalers arrange for the transportation of goods from the manufacturer's location to their own warehouse and subsequently to retailers. They coordinates with shipping companies, freight forwarders, and other logistics providers to ensure timely delivery.    - Wholesalers may offer credit facilities to retailers, allowing them to purchase goods on credit terms and pay later. This helps retailers manage their cash flow and inventory levels.", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2023>1>b", "subject": "Marketing", "year": "2023", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "Outline five factors that would influence the choice of a distribution channel by a producer.", "images": [], "marking_scheme": "- Nature of product: the nature of the product has a bearing on the choice of distribution channel. The durability of the product, unit cost of product, type of product must be considered while determining the distribution channel.    - Nature of market: the geographical width of the market, number of potential buyer, nature of competition has a bearing on selection of distribution channel.    - Size of business: the size of the business, financial strength of the concern determines the channel of distribution. A small producer may sell his distribution.  A small producer may sell his product directly, while a large producer may use a longer distribution channel.    - Cost of channel: distribution process involves cost of transportation, warehousing, storage insurance, material handling, distribution personnel's compensation and interest on inventory carried at different selling points. Higher cost of distribution will result in the increased cost of product.    - Nature of middlemen: the producer must select those middlemen who provide the best marketing services like storage, transportation, credit and packing etc. At the same time the middlemen should ensure various services to customers.", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2023>2>a", "subject": "Marketing", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER", "question": "Mr Oke, the head of the purchasing committee in BIQ Ltd bought a television set for his family.    Explain the first four steps Mr Oke took in buying the television", "images": [], "marking_scheme": "- Need identification: Mr Oke recognized the need to purchase a television set for his family. This step involves identifying the requirements, preferences, and specifications of the product to meet his family's entertainment needs.    - Research and Evaluation: after identifying the need, Mr Oke conducted thorough research on different televisionj models, brands, features and prices. He gathered information from various sources.    - Decision making: once Mr. Oke had gathered sufficient information, he analyzed the avaliable options and compared them against his requirements and budget.    - Purchase and Post-Purchasr Evaluation: after finalizing his decision, Mr Oke proceeded with the actual purchase of the chosen television set. He identified the most reliable retailer and made payment.", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2023>2>b", "subject": "Marketing", "year": "2023", "type": "Theory", "sub_label": "b", "group": "", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : INFLUECING FACTORS", "question": "Mr Oke, the head of the purchasing committee in BIQ Ltd bought a television set for his family.  List and explain four factors that would influence the committee's buying behaviour", "images": [], "marking_scheme": "- Organizational goals and objectives: the committee's buying behaviour is influenced by the goals and objectives of the organization.    - Budget and financial considerations: the financial resources available to the committee can greately influence their buying behaviour.    - Organizational policies and procedures: committees often have to adhere to specific organizational policies and procedures when making purchasing decisions.    - Stakeholders input and influence: committees are composed of multiple individuals representing various departments or functions within the organization.    - Product specifications and quality: the specifications and quality of the product or service being considered will impact the committee's buying behaviour    - Vendor reputation and relationships: the reputation and relationships with potential vendors can influence the committee's buying behaviour.", "marks": "12", "difficulty": "2"}, {"id": "theory>Marketing>2023>3>a", "subject": "Marketing", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "INTERNATIONAL MARKETING : INFLUENCING FACTORS", "question": "JK Ltd, a Nigerian company decides to expand its operational to the South African Market.    State four reason that would have necessitated the company's decision", "images": [], "marking_scheme": "- Access to new customers and markets     - Diversifying its business to reduce risk    - Taking advantage of new opportunities in South Africa    - Increasing profitability through economies of scale", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2023>3>b", "subject": "Marketing", "year": "2023", "type": "Theory", "sub_label": "b", "group": "", "topic": "INTERNATIONAL MARKETING : INFLUENCING FACTORS", "question": "JK Ltd, a Nigerian company decides to expand its operational to the South African Market.  List and explain four entry modes the company could use to enter the South African market", "images": [], "marking_scheme": "- Exporting  - Franchising  - Joint venture  - Wholly owned subsidiary    Exporting:  This mode of entry is suitable for JK Ltd as it requires low investment and allows the company to test the market with minimal risk. The main disadvantage is that it may be difficult to maintain quality control.    Franching:   This mode of entry allows JK Ltd to expand quickly and takes advantage of an already established business with knowledge of the South African market. However, it may be difficult to maintain control over the franchisee.    Joint venture:  This mode of entry allows JK Ltd to share the risks and expenses of entering the South African market with a local company. However, Jk Ltd may lose some control over the operations of the joint venture company.    Wholly owned subsidiary:  This mode of entry gives JK Ltd complete control over its operations in South Africa. However, it requires significant investment and may take longer to establish a presence in the market.", "marks": "12", "difficulty": "2"}, {"id": "theory>Marketing>2023>4>a", "subject": "Marketing", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : FACTORS AFFECTING MARKETING ENVIRONMENT", "question": "List two components each of the 4P's of marketing", "images": [], "marking_scheme": "- Product : Quality, Design    - Price: Cost, Value    - Place: Distribution channels, Location    - Promotion: Advertising, Public relations", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2023>4>b", "subject": "Marketing", "year": "2023", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ENTREPRENUERSHIP IN MARKETING : MANAGEMENT OF MARKET OUTLETS", "question": "List and explain four external factors affecting the marketing environment", "images": [], "marking_scheme": "- Economic factors  - Technological factors  - Political factors  - Sociocultural factors    Economic factors:   Factors such as inflation, interest rates, and income levels can directly impact consumer spending habits and the overall demand for goods and services.    Technological factors:  Technology can create new opportunites for marketers, while also rendering existing products and marketing strategies obsolete.    Political and legal factors:   Changes in laws and regulations related to marketing such as privacy laws, advertising regulations, and product safety requirements, can greatly impact marketing strategies.    Sociocultural factors  Cultural and social factors such as demographics, social trends, and consumer behaviours can influence consumer preferences and the success of marketing campaigns.", "marks": "12", "difficulty": "2"}, {"id": "theory>Marketing>2023>5>a", "subject": "Marketing", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "ENTREPRENUERSHIP IN MARKETING : SOURCES OF FUNDS", "question": "Jo - Bo, a young graduate established a retail outlet in his neighbourhood instead of seeking for a paid employment.    State five activities Jo-Bo would carry out to ensure continuous patronage by customers.", "images": [], "marking_scheme": "- Jo Bo should ensure a different variety of products are available in his retail outlet to cater to different customer preferences and needs.    -  Jo -Bo should focus on providing high-quality products that meet or exceed customers expectations.    - Jo -Bo should offer competitive prices for his products compaired to other retailers in the area.    - Jo - Bo should provide excellent customer service for customer retention.    - Implementing a loyalty program or offering incentives such as discounts or reward points, for repeat customers.    -Jo -Bo should ensure his retail outlet is visually appealing and well organized.    - Jo-Bo should engage in effective marketing strategies to create awareness and attract new customers    - Jo-Bo should actively seek feedback from customers to understand their needs and preferences better.", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2023>5>b", "subject": "Marketing", "year": "2023", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ENTREPRENUERSHIP IN MARKETING : MEANING OF ENTREPRENEURSHIP", "question": "Jo - Bo, a young graduate established a retail outlet in his neighbourhood instead of seeking for a paid employment.  State five benefits Jo -Bo would derive from his decision", "images": [], "marking_scheme": "- By starting his own retail outlet, Jo-Bo can become financially independent.    - Running a business allows Jo-Bo to gain valuable entrepreneurial experience/    - By establishing his retail outlet, Jo-Bo contributes to job creation in his neighborhood.    - As the owner of his business, Jo-Bo has the freedom to set his own working hours and make decisions independently.    - He will be able to learn continously and experience personal growth.    - Building a successful businjess can potentially lead to long term wealth creation for Jo-Bo.", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2023>6>a", "subject": "Marketing", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "PRICING : APPLICATION", "question": "State five factors that a manufacturer would consider before setting prices for his products.", "images": [], "marking_scheme": "- Business goals: before setting a price for the product or service, the manufacturer must first consider the overall marketing objectives.    - Cost: the cost involved with running the business must be worked out. These include the fixed cost and direct costs.    - Customers: know what the customers want from the product or services. Are they driven by the cheapest price or by the value they receive?    - Positioning: Where do you want to be in the marketplace. Will the product be expensive or high -end brand in the industry.    - Competitiors: the manufacturer will have to give permission to do little competitor snooping. What are they charging for different products and services?", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2023>6>b", "subject": "Marketing", "year": "2023", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "Explain five advantages of television over electronic billboard as a medium of advertising.", "images": [], "marking_scheme": "- Large audience: the television has large audience reach than the electronic billboard as a medium of advert.    - Possibility to hear and see: television advert makes it possibvle to see and hear information about the product at the same time.    - Quick for viewer: understanding of advertisement is simple and quick for viewers.    - True form of the product: the true form and colour of the product can be easily seen.    - Gives live and direct display: in this kind of advertising, there is more sensory stimulations as it gives live and direct display.", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2024>1>a>i", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "i", "group": "", "topic": "INTRODUCTION TO MARKETING : BASIC TERMS", "question": "Explain the following terms in marketing:    Needs", "images": [], "marking_scheme": "In marketing, needs refer to the basic requirements or essentials that individuals must satisfy to maintain their health, well-being, or survival. Needs are fundamental and arise from a deficiency or a gap that must be filled. They are inherent and not created by marketing but are crucial in understanding consumer behavior and designing products or services.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2024>1>a>ii", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "ii", "group": "", "topic": "INTRODUCTION TO MARKETING : BASIC TERMS", "question": "Explain the following terms in marketing:    Wants", "images": [], "marking_scheme": "In marketing, wants refer to the desires or preferences that individuals have for specific products or services that go beyond their basic needs. While needs are fundamental and necessary for survival, wants are shaped by personal preferences, cultural influences, and social factors. Wants are not essential for survival but enhance quality of life and personal satisfaction.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2024>1>b", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "INTRODUCTION TO MARKETING : FUNCTIONS", "question": "State four functions of marketing in a company", "images": [], "marking_scheme": "-  Market Research and Analysis:  Marketing conducts research to understand consumer needs, preferences, and market trends. This involves collecting and analyzing data to identify opportunities and challenges in the market.    - Product Development and Management:  Marketing is involved in the creation, design, and management of products and services. This includes determining product features, benefits, and improvements based on consumer feedback and market demand.    - Promotion and Communication:  Marketing develops and implements promotional strategies to communicate the value of products or services to the target audience. This includes advertising, public relations, sales promotions, and digital marketing.    - Sales and Distribution:  Marketing establishes distribution channels and sales strategies to deliver products or services to customers. This includes selecting retail partners, setting up e-commerce platforms, and managing sales teams.", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2024>1>c", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "c", "group": "", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "Explain four concepts of marketing", "images": [], "marking_scheme": "Marketing Concept:  Focuses on understanding and meeting the needs and wants of customers better than competitors. It emphasizes customer orientation, where the primary goal is to satisfy customer needs.    Product Concept:  Centers on the idea that consumers will favor products that offer the best quality, performance, or innovative features. Companies focus on improving and refining their products.    Sales Concept:  Based on the belief that consumers will not buy enough of the company's products unless substantial selling and promotional efforts are made. It emphasizes aggressive sales tactics and promotion.    Societal Marketing Concept:  Extends the marketing concept by integrating social and ethical considerations into marketing strategies. It suggests that companies should also consider the long-term welfare of society and the environment.", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2024>2>a", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "a", "group": "", "topic": "PRODUCTS : MEANING", "question": "Define consumer products", "images": [], "marking_scheme": "Consumer products are goods and services purchased by individuals for personal use rather than for business or industrial purposes. These products are intended to meet the everyday needs and wants of consumers.    Consumer products are categorized based on their intended use and the buying behavior of consumers. They include various types of goods and services that individuals purchase for their personal consumption, as opposed to products used for manufacturing or resale.", "marks": "2", "difficulty": "1"}, {"id": "theory>Marketing>2024>2>b", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "TRANSPORTATION : MEANING,MODE, CHOICE AND IMPORTANCE", "question": "List and explain three modes of transportation a company could use for business", "images": [], "marking_scheme": "-Road Transportation  - Rail Transportation  - Air Transportation       Road Transportation:  Involves the use of trucks, vans, or other vehicles to transport goods over roads. It is highly flexible and suitable for both short and long distances. Road transport can be used for local deliveries, regional distribution, and even long-haul trucking. It allows for door-to-door service and can handle various types of cargo, from small parcels to large shipments.    Rail Transportation:  Utilizes trains to move goods along rail networks. It is cost-effective for transporting large quantities of bulk goods over long distances. Rail transport is ideal for heavy and bulk items such as coal, minerals, and large quantities of manufactured goods. It is generally more fuel-efficient and less affected by traffic compared to road transport.    Air Transportation:  Involves the use of aircraft to transport goods quickly over long distances. Air transport is the fastest mode of transportation, making it suitable for urgent and high-value items. It is often used for international shipments or time-sensitive deliveries. Although it is more expensive compared to road and rail, it offers significant speed advantages and reliability.", "marks": "9", "difficulty": "2"}, {"id": "theory>Marketing>2024>2>c", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "c", "group": "", "topic": "PRODUCTS : CLASSIFICATION", "question": "List and explain three categories of industrial products", "images": [], "marking_scheme": "- Raw Materials  - Component Parts  - Capital Parts    Raw Materials:  Explanation: These are basic materials used in the production of other goods. Raw materials are sourced from natural resources and undergo minimal processing before being used in manufacturing. Examples include minerals, metals, agricultural products, and forestry products. They serve as the foundation for creating finished products.    Component Parts:  These are manufactured items that are used as parts or components in the assembly of final products. Component parts are typically produced to precise specifications and are integrated into larger products during the manufacturing process. Examples include engines, electronic circuits, and gears. They are essential for creating complex machinery and equipment.    Capital Goods:   These are durable goods used in the production of other products or services. Capital goods are typically long-term investments and include machinery, equipment, and tools that help in the manufacturing process. Examples include industrial machines, construction equipment, and factory installations. They are crucial for the production process and often involve significant investment.", "marks": "9", "difficulty": "2"}, {"id": "theory>Marketing>2024>3>a", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "a", "group": "", "topic": "SALES PROMOTION : FORMS", "question": "AB Enterprises is currently experiencing a decline in sales of its products    List eight sales promotional tools the company could use to reverse its sales trend", "images": [], "marking_scheme": "- Discounts and Coupons    - Sales Promotions    - Loyalty Programs    - Bundling    - Sampling    - Trade Shows and Exhibitions    - Advertising Campaigns    - Public Relations (PR) Activities", "marks": "8", "difficulty": "3"}, {"id": "theory>Marketing>2024>3>b", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "SALES PROMOTION : MEANING AND FUNCTIONS", "question": "AB Enterprises is currently experiencing a decline in sales of its products    State six benefits the company would derive from using sales promotional tools", "images": [], "marking_scheme": "-  Increased Sales Volume: Promotional tools can drive more purchases and boost overall sales.    -  Enhanced Brand Awareness: Promotions can improve visibility and recognition of the brand.    -  Improved Customer Acquisition: Attracts new customers by offering incentives or trials.    -  Boosted Customer Loyalty: Encourages repeat business through loyalty programs and rewards.    -  Greater Market Penetration: Helps reach new market segments and expand customer base.    -  Short-Term Revenue Growth: Provides a quick boost in sales and revenue through special offers and discounts.", "marks": "12", "difficulty": "2"}, {"id": "theory>Marketing>2024>4>a", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "a", "group": "", "topic": "MARKET UNIONS AND FACILITATORS : MARKET UNIONS - MEANING AND TYPES", "question": "Yam sellers in a local market formed an association    State four functions the association would perform to its members", "images": [], "marking_scheme": "-  Price Regulation: Establishing fair prices for yam to protect members from market fluctuations and ensure consistent earnings.    -Marketing and Promotion: Promoting members' products collectively to attract more customers and enhance market visibility.    -  Bulk Purchasing: Facilitating bulk purchases of supplies or equipment at discounted rates to reduce costs for members.    -  Training and Support: Providing education on best practices, farming techniques, and business management to improve members' skills and productivity.", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2024>4>b", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "MARKET UNIONS AND FACILITATORS : MARKET FACILITATORS - MEANING, TYPES AND ROLES", "question": "Yam sellers in a local market formed an association    List and explain four types of market facilitator that would assist members of the association in achieving their objectives", "images": [], "marking_scheme": "- Marketing Intermediaries  -Financial Institutions  -Agricultural Extension Services  - Market Research Firms      Marketing Intermediaries:  These include wholesalers and distributors who help in moving yam from sellers to retailers or directly to customers. They assist in expanding market reach and managing distribution logistics.    Financial Institutions:  Banks or microfinance institutions provide loans, credit, and financial services. They help members secure funds for purchasing stock, investing in equipment, or expanding their operations.    Agricultural Extension Services:  These services offer advice and support on farming techniques, pest control, and crop management. They help improve the quality and yield of yams, enhancing overall productivity.    Market Research Firms:  Firms that provide insights into market trends, consumer preferences, and competitive analysis. They help the association make informed decisions on pricing, product positioning, and market opportunities.", "marks": "12", "difficulty": "2"}, {"id": "theory>Marketing>2024>5>a", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "a", "group": "", "topic": "ENTREPRENUERSHIP IN MARKETING : SOURCES OF FUNDS", "question": "Adamu intends to open a store to sell detergents as a major distributor for companies in the country.    List and explain four sources from which Adamu could get funds to finance the business", "images": [], "marking_scheme": "- Bank Loans  - Personal Savings  - Investment from Family and Friends  - Venture Capital      Bank Loans:  Adamu can obtain a loan from a bank, which would provide a lump sum of capital that he needs to start and run his business. The loan would need to be repaid with interest over a specified period.    Personal Savings:  Using personal savings is a common way to finance a business. Adamu can use his own funds accumulated over time to cover startup costs and initial expenses.    Investment from Family and Friends:  Adamu could seek financial support from family members and friends who are willing to invest in his business. This can be in the form of loans or equity investment.    Venture Capital:  Venture capitalists invest in startups and emerging businesses in exchange for equity or ownership stakes. Adamu could attract venture capital funding if he presents a strong business plan and growth potential.", "marks": "12", "difficulty": "2"}, {"id": "theory>Marketing>2024>5>b", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "ENTREPRENUERSHIP IN MARKETING : FACTORS AFFECTING LOCATION OF A MARKET OUTLET", "question": "Adamu intends to open a store to sell detergents as a major distributor for companies in the country.    State four factors that would influence Adamu's choice of the location for the business", "images": [], "marking_scheme": "Proximity to Target Market:  Choosing a location close to the target customers ensures easy access and convenience, which can drive higher sales and customer traffic.    Accessibility and Transportation:  The location should be easily accessible by major roads or transport routes to facilitate the delivery of goods and attract customers. Good transportation links also aid in efficient logistics and supply chain management.    Cost of Rent or Purchase:  The cost of renting or purchasing property in the area affects the overall expenses. Adamu needs to balance affordability with the potential for high sales and visibility.    Competition and Market Saturation:  Assessing the level of competition and market saturation in the area helps determine if there is room for a new distributor. A location with less competition or unmet demand can offer better growth opportunities.", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2024>6>a>i", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "i", "group": "", "topic": "INTRODUCTION TO MARKETING : MEANING OF MARKETING", "question": "OJ Ltd is a consumer goods manufacturing firm. They sell to retail outlets throughout the country. The company intends to increase its market share.    Explain the term in relation to the company's business activities:    Demand", "images": [], "marking_scheme": "In relation to OJ Ltd's business activities, demand refers to the quantity of consumer goods that retail outlets across the country are willing and able to purchase from the company at a given price.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2024>6>a>ii", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "ii", "group": "", "topic": "PRODUCTS : MEANING", "question": "OJ Ltd is a consumer goods manufacturing firm. They sell to retail outlets throughout the country. The company intends to increase its market share.    Explain the term in relation to the company's business activities:  Product", "images": [], "marking_scheme": "In relation to OJ Ltd's business activities, product refers to the consumer goods that the company manufactures and sells to retail outlets throughout the country.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2024>6>a>iii", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "iii", "group": "", "topic": "MARKETS : CLASSIFICATION", "question": "OJ Ltd is a consumer goods manufacturing firm. They sell to retail outlets throughout the country. The company intends to increase its market share.    Explain the term in relation to the company's business activities:  Market", "images": [], "marking_scheme": "In relation to OJ Ltd's business activities, market refers to the collection of retail outlets and consumers throughout the country that purchase and sell the company's consumer goods.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2024>6>b", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "OJ Ltd is a consumer goods manufacturing firm. They sell to retail outlets throughout the country. The company intends to increase its market share.    Explain the term in relation to the company's business activities:  Outline two types of distribution channels the company could adopt", "images": [], "marking_scheme": "Direct Distribution Channel:  OJ Ltd sells its products directly to retail outlets without involving intermediaries. This could be done through a company-owned sales force or a direct sales team. This approach allows for better control over the distribution process, direct communication with retailers, and potentially higher profit margins.    Indirect Distribution Channel:  OJ Ltd uses intermediaries such as wholesalers, distributors, or brokers to reach retail outlets. These intermediaries handle the distribution, warehousing, and logistics of the products. This method can help the company reach a broader market more efficiently and leverage the intermediaries' established networks and expertise.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2024>6>c>i", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "i", "group": "", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "State three functions each of the following channel members the company could use:    wholesaler", "images": [], "marking_scheme": "Bulk Purchasing and Storage:  Wholesalers buy large quantities of products from manufacturers like OJ Ltd and store them in warehouses. This reduces the need for manufacturers to manage large inventories and allows retailers to purchase smaller quantities as needed.    Distribution and Logistics:  They handle the logistics of distributing products to various retail outlets. This includes managing transportation, inventory control, and order fulfillment, ensuring that products reach the retailers efficiently and on time.    Market Information and Sales Support:  Wholesalers provide valuable market information and insights about consumer preferences and market trends. They also offer sales support to retailers, including marketing materials and promotional activities, helping to drive sales and improve product visibility.", "marks": "6", "difficulty": "2"}, {"id": "theory>Marketing>2024>6>c>ii", "subject": "Marketing", "year": "2024", "type": "Theory", "sub_label": "ii", "group": "", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "State three functions each of the following channel members the company could use:    retailer", "images": [], "marking_scheme": "Product Sales and Customer Service:  Retailers sell products directly to end consumers and provide customer service, including assisting with product selection, handling returns, and addressing customer inquiries and complaints.    Inventory Management:  They manage inventory levels by ordering products from wholesalers or manufacturers and ensuring that they have the right amount of stock to meet consumer demand. This includes tracking inventory, managing stock replenishment, and handling storage.    Marketing and Promotion:  Retailers promote products through various marketing strategies, such as in-store displays, special promotions, and advertising. They play a key role in attracting customers to their stores and enhancing product visibility.", "marks": "6", "difficulty": "2"}, {"id": "theory>Marketing>2025>1>a", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "a", "group": "", "topic": "PRODUCTS : CLASSIFICATION", "question": "Mr. John, the purchasing officer of Ajax Ltd, bought an industrial printer for his company's use and packs of noodles for his daughter's birthday party.    Identify the two types of products bought by Mr. John", "images": [], "marking_scheme": "Mr. John bought two types of products: an industrial printer and packs of noodles. The industrial printer is a capital good, which is a durable product used in the production of goods or services, while the packs of noodles are consumer goods, specifically a type of convenience product that is purchased for immediate consumption.", "marks": "2", "difficulty": "1"}, {"id": "theory>Marketing>2025>1>b", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "PRODUCTS : DISTINCTION BETWEEN CLASSES OF PRODUCTS", "question": "Mr. John, the purchasing officer of Ajax Ltd, bought an industrial printer for his company's use and packs of noodles for his daughter's birthday party.    State four differences between the two types of products bought by Mr. John", "images": [], "marking_scheme": "The four differences between the two types of products bought by Mr. John are as follows:  1. Nature of Use: The industrial printer is used for business purposes, while the packs of noodles are for personal consumption.  2. Durability: The industrial printer is a durable good, expected to last for several years, whereas the packs of noodles are perishable goods with a short shelf life.  3. Cost: The industrial printer is likely to be significantly more expensive than the packs of noodles, which are relatively low-cost items.  4. Purchase Decision: The purchase of the industrial printer involves a more complex decision-making process due to its high cost and business implications, while the purchase of noodles is a simple, routine decision.", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2025>1>c", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "c", "group": "", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER", "question": "Mr. John, the purchasing officer of Ajax Ltd, bought an industrial printer for his company's use and packs of noodles for his daughter's birthday party.    Explain the five stages in decision making process thet Mr John would have followed in the purchases of the noodles.", "images": [], "marking_scheme": "The five stages in the decision-making process that Mr. John would have followed in the purchase of the noodles are:  1. Problem Recognition: Mr. John recognizes the need for food for his daughter's birthday party, prompting him to consider purchasing noodles.  2. Information Search: He may gather information about different types of noodles available, including brands, prices, and nutritional value, either through online research or by visiting local stores.  3. Evaluation of Alternatives: Mr. John evaluates the options based on factors such as price, taste, and brand reputation. He may compare different brands of noodles to determine which one best meets his needs.  4. Purchase Decision: After evaluating the alternatives, Mr. John decides on a specific brand and quantity of noodles to purchase, considering factors like budget and availability.  5. Post-Purchase Evaluation: After the purchase, Mr. John may reflect on his decision, considering whether the noodles met his expectations in terms of taste and quality during the party, which could influence future purchasing decisions.", "marks": "10", "difficulty": "3"}, {"id": "theory>Marketing>2025>2>a", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "a", "group": "", "topic": "SALES PROMOTION : MEANING AND FUNCTIONS", "question": "What is sales promotion?", "images": [], "marking_scheme": "Sales promotion refers to a variety of marketing strategies and techniques aimed at increasing the sales of a product or service in the short term. These strategies can include discounts, coupons, contests, free samples, and other incentives designed to encourage consumers to make a purchase. The goal of sales promotion is to stimulate immediate demand and boost sales volume, often used in conjunction with advertising and public relations efforts.", "marks": "2", "difficulty": "1"}, {"id": "theory>Marketing>2025>2>b>i", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "i", "group": "", "topic": "SALES PROMOTION : FORMS", "question": "Explain the following forms of sales promotion:    coupon", "images": [], "marking_scheme": "A coupon is a promotional tool that offers consumers a discount or rebate on a specific product or service. Coupons can be distributed through various channels, including newspapers, magazines, online platforms, and in-store promotions. They serve as an incentive for consumers to try a product, encourage repeat purchases, and can help to increase brand loyalty. Coupons can be either digital or physical, and they typically have an expiration date, creating a sense of urgency for consumers to use them before they expire.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2025>2>b>ii", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "ii", "group": "", "topic": "SALES PROMOTION : FORMS", "question": "Explain the following forms of sales promotion:  sample", "images": [], "marking_scheme": "Sales promotion through samples involves providing potential customers with a free sample of a product. This strategy is designed to encourage trial and increase the likelihood of purchase. By allowing consumers to experience the product firsthand, companies can effectively demonstrate its quality and benefits. Samples can be distributed in various ways, such as through in-store promotions, events, or direct mail. The goal is to create a positive impression that leads to future sales.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2025>2>b>iii", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "iii", "group": "", "topic": "SALES PROMOTION : FORMS", "question": "Explain the following forms of sales promotion:  premium", "images": [], "marking_scheme": "Premiums are promotional items that are offered to customers as an incentive to purchase a product or service. These can take the form of free gifts, discounts, or exclusive items that add value to the purchase. Premiums are effective because they enhance the perceived value of the product, encouraging customers to buy more or choose one brand over another. For example, a company might offer a free tote bag with the purchase of a certain amount of their products, which can increase customer loyalty and repeat purchases.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2025>2>b>iv", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "iv", "group": "", "topic": "SALES PROMOTION : FORMS", "question": "Explain the following forms of sales promotion:  contest", "images": [], "marking_scheme": "Contests are a form of sales promotion that encourages consumer participation by offering prizes for specific actions, such as submitting entries or completing tasks. This strategy not only engages customers but also generates excitement and buzz around a brand. Contests can be structured in various ways, such as sweepstakes, skill-based competitions, or social media challenges. The key is to create a compelling incentive that motivates consumers to participate, thereby increasing brand awareness and customer interaction.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2025>2>c", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "c", "group": "", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "State five advantages of magazine as an advertising medium", "images": [], "marking_scheme": "1. Wide Reach: Magazines have a broad distribution network, allowing advertisers to reach a large audience effectively. 2. Targeted Audience: Advertisers can select magazines that cater to specific demographics, ensuring their message reaches the right consumers. 3. High Engagement: Readers often spend more time with magazines, leading to better retention of advertisements. 4. Visual Appeal: Magazines allow for high-quality visuals, which can enhance the attractiveness of the advertisement. 5. Credibility: Magazines are often viewed as credible sources of information, which can lend authority to the advertisements they contain.", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2025>3>a", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "a", "group": "", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "Premium Ltd is a manufacturer of confectioneries that sells its products to distributors nationwide.    State five functions the distributors would perform in the company", "images": [], "marking_scheme": "1. Distribution: Distributors are responsible for transporting products from the manufacturer to various retail outlets, ensuring that products are available where consumers can purchase them. 2. Inventory Management: They manage stock levels, ensuring that retailers have enough products to meet consumer demand without overstocking. 3. Marketing Support: Distributors often assist manufacturers in marketing their products, providing promotional materials and support to retailers. 4. Customer Service: They handle inquiries and issues from retailers, providing support and ensuring satisfaction with the products. 5. Market Feedback: Distributors gather feedback from retailers and consumers, which can be valuable for manufacturers in improving products and marketing strategies.", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2025>3>b", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "TRANSPORTATION : FACTORS AFFECTING CHOICE OF TRANSPORTATION", "question": "Premium Ltd is a manufacturer of confectioneries that sells its products to distributors nationwide.    State five factors the company would consider in choosing a mode of transporting its products to distributors.", "images": [], "marking_scheme": "When Premium Ltd, a manufacturer of confectioneries, considers a mode of transporting its products to distributors, it must evaluate several factors to ensure efficiency and cost-effectiveness. Here are five key factors:    1. Cost: The transportation cost is a critical factor. Premium Ltd needs to analyze the expenses associated with different modes of transport (e.g., road, rail, air, sea) and choose the one that fits its budget while ensuring timely delivery.    2. Speed: The urgency of delivery can influence the choice of transport. If the products need to reach distributors quickly, Premium Ltd may opt for air freight despite its higher cost, whereas less urgent deliveries might be suitable for road or rail transport.    3. Distance: The geographical distance between the manufacturing facility and the distributors plays a significant role. Longer distances may require more robust transport solutions, while shorter distances might allow for more flexible options.    4. Product Nature: The characteristics of the confectioneries, such as perishability, fragility, and packaging, will affect the choice of transport. For instance, delicate items may require specialized handling and transport conditions.    5. Regulatory Compliance: Premium Ltd must consider any legal regulations regarding the transportation of food products, including safety standards and documentation requirements, which can vary by region and mode of transport.", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2025>4>a", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "a", "group": "", "topic": "MARKET UNIONS AND FACILITATORS : MARKET UNIONS - MEANING AND TYPES", "question": "What is market union?", "images": [], "marking_scheme": "A market union, also known as a customs union, is an agreement between two or more countries to eliminate trade barriers, such as tariffs and quotas, among themselves while maintaining a common external tariff against non-member countries. This arrangement allows for the free movement of goods and services between member countries, fostering economic cooperation and integration. Market unions aim to enhance trade efficiency, promote economic growth, and create a larger market for businesses within the union. By standardizing regulations and reducing costs associated with trade, market unions can lead to increased competitiveness and consumer benefits.", "marks": "2", "difficulty": "1"}, {"id": "theory>Marketing>2025>4>b", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "MARKET UNIONS AND FACILITATORS : ROLES OF MARKET UNIONS", "question": "State four roles performed by market unions to their members", "images": [], "marking_scheme": "Market unions perform several essential roles for their members, which include:    1. Facilitating Trade: Market unions eliminate tariffs and trade barriers among member countries, making it easier and cheaper for businesses to trade with one another.    2. Economic Integration: They promote economic cooperation and integration among member states, leading to a more unified economic policy and shared resources.    3. Standardization of Regulations: Market unions often work to harmonize regulations and standards across member countries, which simplifies compliance for businesses and enhances product safety and quality.    4. Collective Bargaining Power: By uniting, member countries can negotiate better trade deals and agreements with non-member countries, leveraging their combined market size to secure favorable terms.", "marks": "8", "difficulty": "1"}, {"id": "theory>Marketing>2025>4>c", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "c", "group": "", "topic": "PACKAGING", "question": "State five advantages of packaging to a product", "images": [], "marking_scheme": "Packaging plays a crucial role in marketing and product presentation. Here are five advantages of packaging to a product:    1. Protection: Packaging protects products from damage during transportation and storage, ensuring that they reach consumers in good condition.    2. Preservation: For perishable goods, packaging can help preserve freshness and extend shelf life by providing barriers against moisture, air, and light.    3. Branding: Effective packaging serves as a marketing tool that communicates the brand identity and values, helping to differentiate the product in a competitive market.    4. Information: Packaging provides essential information to consumers, including ingredients, usage instructions, and nutritional facts, which can influence purchasing decisions.    5. Convenience: Well-designed packaging enhances user convenience, making it easier to open, use, and store products, which can improve customer satisfaction and loyalty.", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2025>5>a", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "a", "group": "", "topic": "ICT IN MARKETING : E-MARKETING - MEANING, IMPORTANCE", "question": "What is e-marketing?", "images": [], "marking_scheme": "E-marketing, also known as electronic marketing or online marketing, refers to the use of digital channels and technologies to promote products and services. This includes a wide range of activities such as email marketing, social media marketing, search engine optimization (SEO), content marketing, and online advertising. E-marketing allows businesses to reach a global audience, engage with customers in real-time, and analyze consumer behavior through data analytics. The rise of the internet and mobile devices has transformed traditional marketing strategies, making e-marketing an essential component of modern business practices. It enables targeted marketing efforts, cost-effective campaigns, and measurable results, which can significantly enhance a company's marketing effectiveness.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2025>5>b", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "ICT IN MARKETING : E-MARKETING - MEANING, IMPORTANCE", "question": "State four benefit of e-marketing?", "images": [], "marking_scheme": "E-marketing, or electronic marketing, refers to the use of digital channels to promote products and services. Here are four benefits of e-marketing:    1. Global Reach: E-marketing allows businesses to reach a global audience without the geographical limitations of traditional marketing. This means that a small business can market its products to customers around the world, increasing its potential customer base significantly.    2. Cost-Effectiveness: Compared to traditional marketing methods such as print or television advertising, e-marketing is often more affordable. Businesses can utilize social media, email marketing, and search engine optimization (SEO) to promote their products at a fraction of the cost.    3. Measurable Results: E-marketing provides businesses with the ability to track and analyze their marketing efforts in real-time. Tools like Google Analytics allow companies to see how many people visited their website, what actions they took, and how they found the site, enabling data-driven decision-making.    4. Targeted Marketing: E-marketing allows for more precise targeting of specific demographics. Businesses can tailor their marketing messages to specific groups based on their interests, behaviors, and demographics, leading to higher conversion rates and more effective marketing campaigns.", "marks": "8", "difficulty": "2"}, {"id": "theory>Marketing>2025>5>c", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "c", "group": "", "topic": "INTERNATIONAL MARKETING : INFLUENCING FACTORS", "question": "State five reasons a company would want to engage in international marketing", "images": [], "marking_scheme": "Companies engage in international marketing for several reasons. Here are five key reasons:    1. Market Expansion: By entering international markets, companies can expand their customer base beyond domestic borders. This is particularly important for businesses in saturated markets where growth opportunities are limited.    2. Diversification of Revenue: International marketing allows companies to diversify their revenue streams. By selling in multiple countries, businesses can reduce their dependence on a single market and mitigate risks associated with economic downturns in their home country.    3. Access to New Resources: Engaging in international marketing can provide companies with access to new resources, including raw materials, labor, and technology. This can lead to cost savings and improved product offerings.    4. Competitive Advantage: Companies that successfully enter international markets can gain a competitive advantage over their rivals. By establishing a presence in multiple countries, they can leverage their brand and reputation globally.    5. Economies of Scale: International marketing can help companies achieve economies of scale by increasing production and distribution efficiencies. As companies grow and expand their operations, they can lower their per-unit costs, leading to higher profit margins.", "marks": "10", "difficulty": "2"}, {"id": "theory>Marketing>2025>6>a>i", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "i", "group": "", "topic": "INTRODUCTION TO MARKETING : BASIC TERMS", "question": "Explain the following marketing terms:    supply", "images": [], "marking_scheme": "The term 'supply' in marketing refers to the total amount of a product or service that is available to consumers. It is a fundamental concept in economics and marketing that describes the relationship between the quantity of a good that producers are willing to sell and the price of that good. The law of supply states that, all else being equal, an increase in the price of a good will lead to an increase in the quantity supplied. This is because higher prices incentivize producers to manufacture more of the product to maximize profits. Supply can be influenced by various factors, including production costs, technology, and the number of suppliers in the market.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2025>6>a>ii", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "ii", "group": "", "topic": "INTRODUCTION TO MARKETING : BASIC TERMS", "question": "Explain the following marketing terms:  wants", "images": [], "marking_scheme": "In marketing, 'wants' refer to the specific desires or preferences of consumers that are shaped by their culture, personality, and individual experiences. While needs are basic human requirements (such as food, water, and shelter), wants are more specific and can vary widely among individuals. For example, a person may need food but want a specific type of cuisine, such as Italian or Chinese. Understanding consumer wants is crucial for marketers as it helps them tailor their products and marketing strategies to meet the desires of their target audience. By effectively addressing consumer wants, businesses can enhance customer satisfaction and loyalty.", "marks": "2", "difficulty": "2"}, {"id": "theory>Marketing>2025>6>b", "subject": "Marketing", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "Wox Ltd operates on marketing and product concepts while Manti Ltd operates on production and selling concepts.    State two features each of the concept used by the two companies.", "images": [], "marking_scheme": "Wox Ltd and Manti Ltd operate under different marketing concepts, which influence their strategies and operations. Here are two features of each concept:    Wox Ltd (Marketing and Product Concepts):  1. Customer Orientation: Wox Ltd focuses on understanding and meeting the needs and preferences of its customers. This involves conducting market research to gather insights about consumer behavior and preferences, allowing the company to develop products that resonate with its target audience.    2. Innovation and Quality: The product concept emphasizes the importance of product quality and innovation. Wox Ltd likely invests in research and development to create superior products that stand out in the market, ensuring that they meet customer expectations and provide value.    Manti Ltd (Production and Selling Concepts):  1. Efficiency in Production: Manti Ltd operates on the production concept, which prioritizes efficiency in manufacturing and distribution. The company focuses on producing goods at a lower cost and in larger quantities to maximize output and minimize expenses.    2. Aggressive Selling: The selling concept emphasizes the need for aggressive sales tactics to persuade customers to purchase products. Manti Ltd likely employs strong promotional strategies and sales techniques to drive sales, even if the products do not necessarily meet the specific needs of consumers.", "marks": "16", "difficulty": "2"}];